const response = $input.item.json;
const dadosOriginais = $input.first().json;

const rawText = response.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let dados = JSON.parse(rawText.replace(/```json|```/g, '').trim());

// ========================================
// FUNÇÃO AUXILIAR - CONVERTER VALOR BR PARA NÚMERO
// ========================================
function parseFloatBR(valor) {
  if (typeof valor === 'number') return valor;
  if (!valor) return 0;
  return parseFloat(valor.toString().replace(/\./g, '').replace(',', '.')) || 0;
}

// ========================================
// FUNÇÃO AUXILIAR - FORMATAR NÚMERO PARA BR
// ========================================
function formatarValorBR(valor) {
  return valor.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

// ========================================
// CALCULAR COMPRAS A PARTIR DAS ENTRADAS
// ========================================
// Soma apenas itens da seção ENTRADAS que contêm "COMPRA" na descrição
// SAÍDAS e SERVIÇOS não são considerados

let totalCompras = 0;
let itensCompras = [];

// Processar ENTRADAS - somar apenas itens com "COMPRA" na descrição
// SAÍDAS e SERVIÇOS não são considerados no cálculo de compras
if (dados.entradas && Array.isArray(dados.entradas)) {
  for (const entrada of dados.entradas) {
    const descricao = (entrada.descricao || '').toUpperCase();
    const valor = parseFloatBR(entrada.valor);

    // Verificar se é uma compra (contém "COMPRA" na descrição)
    if (descricao.includes('COMPRA')) {
      totalCompras += valor;
      itensCompras.push({
        codigo: entrada.codigo,
        descricao: entrada.descricao,
        valor: entrada.valor
      });
      console.log(`✅ Compra encontrada: ${entrada.descricao} = R$ ${entrada.valor}`);
    } else {
      console.log(`⏭️ Ignorando entrada (não é compra): ${entrada.descricao}`);
    }
  }
}

// comprasMes = apenas soma das ENTRADAS com "COMPRA" (sem subtrair devoluções)
console.log(`📊 Total Compras (ENTRADAS): R$ ${formatarValorBR(totalCompras)}`);

// ========================================
// RETORNAR DADOS PROCESSADOS
// ========================================
return {
  reportId: dadosOriginais.reportId,
  documentoIndex: dadosOriginais.documentoIndex,
  documentoNome: dadosOriginais.documentoNome,
  clienteId: dadosOriginais.clienteId,
  clienteNome: dadosOriginais.clienteNome,
  regimeTributario: dadosOriginais.regimeTributario,
  agenteProcessador: 'AGENTE_4_NOTAS',
  ...dados,
  // Dados de compras (apenas ENTRADAS com "COMPRA" na descrição)
  compras: {
    total: formatarValorBR(totalCompras),
    itensCompras: itensCompras
  },
  comprasMes: formatarValorBR(totalCompras),  // Soma das ENTRADAS com "COMPRA"
  timestampProcessamento: new Date().toISOString()
};

// Pegar a resposta do Gemini do item atual
const item = $input.item.json;

// Extrair o texto da resposta do Gemini
const rawText = item.candidates?.[0]?.content?.parts?.[0]?.text || '{}';

// Limpar e fazer parse do JSON
let dados;
try {
  const cleanText = rawText.replace(/```json|```/g, '').trim();
  dados = JSON.parse(cleanText);
} catch (error) {
  throw new Error(`Erro ao parsear JSON do Agente 3: ${error.message}\nTexto recebido: ${rawText}`);
}

// Pegar dados originais que vieram antes (do documento)
// Estes dados devem estar no item atual, não em $input.first()
const dadosOriginais = {
  reportId: item.reportId || item.dados?.reportId,
  documentoIndex: item.documentoIndex || item.dados?.documentoIndex,
  documentoNome: item.documentoNome || item.dados?.documentoNome || 'Folha de Pagamento',
  clienteId: item.clienteId || item.dados?.clienteId,
  clienteNome: item.clienteNome || item.dados?.clienteNome,
  regimeTributario: item.regimeTributario || item.dados?.regimeTributario
};

// Montar o resultado final
const resultado = {
  ...dadosOriginais,
  agenteProcessador: 'AGENTE_3_FOLHA',
  ...dados,
  timestampProcessamento: new Date().toISOString(),
  temErro: false
};

// IMPORTANTE: Retornar no formato correto do N8N
return { json: resultado };

const geminiResponse = $input.item.json;
const dadosOriginais = $input.first().json;

// ========================================
// EXTRAI E LIMPA RESPOSTA
// ========================================
const rawText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const cleanText = rawText.replace(/```json|```/g, '').trim();

// ========================================
// PARSE SEGURO COM VALIDAÇÃO
// ========================================
let dadosExtraidos;
try {
  dadosExtraidos = JSON.parse(cleanText);

  // Valida campos obrigatórios
  if (!dadosExtraidos.razaoSocial || !dadosExtraidos.cnpj) {
    throw new Error('Resposta incompleta - faltam dados básicos');
  }

} catch (error) {
  console.error('❌ Erro ao processar Agente 2 (PGDAS):', error.message);
  console.error('📄 Resposta recebida:', rawText.substring(0, 500));

  // Fallback com estrutura mínima
  dadosExtraidos = {
    razaoSocial: dadosOriginais.clienteNome || 'Não identificado',
    cnpj: dadosOriginais.cnpjDetectado || '00.000.000/0000-00',
    periodo: dadosOriginais.periodoDetectado || '00/0000',
    receitaBrutaMes: '0,00',
    receitaBrutaAcumulada: '0,00',
    aliquota: '0,00',
    valorDAS: '0,00',
    anexo: null,
    aplicouFatorR: false,
    dataVencimentoDAS: null,
    comprasMes: '0,00',
    comprasAcumuladas: '0,00',
    somenteGuia: true,
    receitasMensaisAnoCorrente: [],
    folhasMensais: [],
    estabelecimentos: [],  // ← ADICIONADO
    observacoes: `Erro no processamento: ${error.message}`,
    _erro: true
  };
}

// ========================================
// GARANTE CAMPOS DE HISTÓRICO EXISTEM
// ========================================
if (!dadosExtraidos.receitasMensaisAnoCorrente) {
  dadosExtraidos.receitasMensaisAnoCorrente = [];
}

if (!dadosExtraidos.folhasMensais) {
  dadosExtraidos.folhasMensais = [];
}

// ========================================
// ✅ GARANTE CAMPO ESTABELECIMENTOS EXISTE
// ========================================
if (!dadosExtraidos.estabelecimentos) {
  dadosExtraidos.estabelecimentos = [];
}

// ========================================
// ✅ GARANTE CAMPO IMPOSTOS MENSAIS EXISTE (CRÍTICO)
// ========================================
if (!dadosExtraidos.impostosMensais) {
  // Se não extraiu histórico, cria array com pelo menos o mês atual
  dadosExtraidos.impostosMensais = [
    {
      mes: dadosExtraidos.periodo,
      valor: dadosExtraidos.valorDAS
    }
  ];
  console.log('⚠️ impostosMensais não encontrado - criado com mês atual');
} else {
  // Valida se o mês atual está no array
  const mesAtualNoArray = dadosExtraidos.impostosMensais.some(
    i => i.mes === dadosExtraidos.periodo
  );

  if (!mesAtualNoArray) {
    // Adiciona o mês atual se não estiver
    dadosExtraidos.impostosMensais.push({
      mes: dadosExtraidos.periodo,
      valor: dadosExtraidos.valorDAS
    });

    // Ordena por data
    dadosExtraidos.impostosMensais.sort((a, b) => {
      const [mesA, anoA] = a.mes.split('/').map(Number);
      const [mesB, anoB] = b.mes.split('/').map(Number);
      return (anoA * 12 + mesA) - (anoB * 12 + mesB);
    });

    console.log('✓ Mês atual adicionado ao impostosMensais');
  }
}

// ========================================
// VALIDAÇÕES E LOGS
// ========================================
console.log('=== AGENTE 2 - PGDAS PROCESSADO ===');
console.log('Tipo:', dadosExtraidos.somenteGuia ? 'Apenas DAS' : 'PGDAS Completo');
console.log('Razão Social:', dadosExtraidos.razaoSocial);
console.log('Receita Mês:', dadosExtraidos.receitaBrutaMes);
console.log('Receita Acumulada:', dadosExtraidos.receitaBrutaAcumulada);
console.log('Anexo:', dadosExtraidos.anexo);
console.log('Fator R:', dadosExtraidos.aplicouFatorR ? 'Sim' : 'Não');
console.log('Meses de Receita:', dadosExtraidos.receitasMensaisAnoCorrente.length);
console.log('Meses de Folha:', dadosExtraidos.folhasMensais.length);
console.log('Meses de Impostos:', dadosExtraidos.impostosMensais.length);  // ← NOVO
console.log('Estabelecimentos:', dadosExtraidos.estabelecimentos.length);

// Alerta se PGDAS completo mas sem histórico
if (!dadosExtraidos.somenteGuia && dadosExtraidos.receitasMensaisAnoCorrente.length === 0) {
  console.warn('⚠️ PGDAS completo, mas histórico de receitas não foi extraído!');
}

// ✅ Alerta se há múltiplos estabelecimentos
if (dadosExtraidos.estabelecimentos.length > 1) {
  console.log('✅ Múltiplos estabelecimentos detectados:', dadosExtraidos.estabelecimentos.length);
}

// ========================================
// ESTRUTURA FINAL
// ========================================
return {
  // === IDENTIFICAÇÃO ===
  reportId: dadosOriginais.reportId,
  documentoIndex: dadosOriginais.documentoIndex,
  documentoNome: dadosOriginais.documentoNome,
  clienteId: dadosOriginais.clienteId,
  clienteNome: dadosOriginais.clienteNome,
  regimeTributario: dadosOriginais.regimeTributario,

  // === AGENTE ===
  agenteProcessador: 'AGENTE_2_PGDAS',
  confiancaClassificacao: dadosOriginais.confianca,

  // === DADOS EXTRAÍDOS ===
  razaoSocial: dadosExtraidos.razaoSocial,
  cnpj: dadosExtraidos.cnpj,
  periodo: dadosExtraidos.periodo,
  receitaBrutaMes: dadosExtraidos.receitaBrutaMes,
  receitaBrutaAcumulada: dadosExtraidos.receitaBrutaAcumulada,
  aliquota: dadosExtraidos.aliquota,
  valorDAS: dadosExtraidos.valorDAS,
  anexo: dadosExtraidos.anexo,
  aplicouFatorR: dadosExtraidos.aplicouFatorR,
  dataVencimentoDAS: dadosExtraidos.dataVencimentoDAS,
  comprasMes: dadosExtraidos.comprasMes,
  comprasAcumuladas: dadosExtraidos.comprasAcumuladas,
  somenteGuia: dadosExtraidos.somenteGuia,

  // === DADOS HISTÓRICOS ===
  receitasMensaisAnoCorrente: dadosExtraidos.receitasMensaisAnoCorrente,
  folhasMensais: dadosExtraidos.folhasMensais,
  impostosMensais: dadosExtraidos.impostosMensais,  // ← NOVO

  // === ✅ ESTABELECIMENTOS (NOVO) ===
  estabelecimentos: dadosExtraidos.estabelecimentos,

  // === METADADOS ===
  observacoes: dadosExtraidos.observacoes,
  timestampProcessamento: new Date().toISOString(),
  temErro: dadosExtraidos._erro || false,

  // === DEBUG (remover em produção) ===
  _debug: {
    respostaOriginal: rawText.substring(0, 800),
    file_uri: dadosOriginais.file_uri,
    historicoExtraido: {
      receitas: dadosExtraidos.receitasMensaisAnoCorrente.length > 0,
      folhas: dadosExtraidos.folhasMensais.length > 0,
      impostos: dadosExtraidos.impostosMensais.length > 0,  // ← NOVO
      estabelecimentos: dadosExtraidos.estabelecimentos.length > 0
    }
  }
};

const geminiResponse = $input.item.json;
const dadosOriginais = $input.first().json;

// Extrai o JSON da resposta
const rawText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const cleanText = rawText.replace(/```json|```/g, '').trim();

// Parse seguro
let dadosExtraidos;
try {
  dadosExtraidos = JSON.parse(cleanText);

  // Valida se tem campos obrigatórios
  if (!dadosExtraidos.totalMovimentoReal) {
    throw new Error('Resposta incompleta - falta totalMovimentoReal');
  }

} catch (error) {
  console.error('❌ Erro ao processar Agente 1:', error.message);
  console.error('📄 Resposta recebida:', rawText);

  // Fallback com estrutura vazia
  dadosExtraidos = {
    cnpj: dadosOriginais.cnpjDetectado,
    periodo: dadosOriginais.periodoDetectado,
    banco: 'Não identificado',
    vendasCartao: {
      stone: '0,00',
      cielo: '0,00',
      pagBank: '0,00',
      rede: '0,00',
      getnet: '0,00',
      mercadoPago: '0,00',
      outras: '0,00',
      total: '0,00'
    },
    pix: { total: '0,00', quantidade: 0 },
    depositos: { total: '0,00', quantidade: 0 },
    transferenciasRecebidas: { total: '0,00', quantidade: 0, detalhes: '' },  // ← ADICIONADO
    transferenciasEntreCnpjs: { total: '0,00', quantidade: 0, detalhes: '' },
    totalMovimentoReal: '0,00',
    observacoes: `Erro: ${error.message}`,
    _erro: true
  };
}

// Função para converter valores BR para número
const parseValorBR = (valor) => {
  if (!valor || valor === '0,00') return 0;
  return parseFloat(valor.replace(/\./g, '').replace(',', '.'));
};

// ========================================
// VALIDAÇÃO CORRIGIDA DO CÁLCULO
// ========================================

const totalCartao = parseValorBR(dadosExtraidos.vendasCartao?.total);
const totalPix = parseValorBR(dadosExtraidos.pix?.total);
const totalDepositos = parseValorBR(dadosExtraidos.depositos?.total);
const totalTransfRecebidas = parseValorBR(dadosExtraidos.transferenciasRecebidas?.total);  // ← ADICIONADO
const totalTransfEntreCnpjs = parseValorBR(dadosExtraidos.transferenciasEntreCnpjs?.total);

// CÁLCULO CORRETO
const movimentoCalculado = totalCartao + totalPix + totalDepositos + totalTransfRecebidas - totalTransfEntreCnpjs;

const movimentoInformado = parseValorBR(dadosExtraidos.totalMovimentoReal);
const diferenca = Math.abs(movimentoCalculado - movimentoInformado);

// Log para debug
console.log('=== VALIDAÇÃO MOVIMENTO FINANCEIRO ===');
console.log('Vendas Cartão:', totalCartao.toFixed(2));
console.log('PIX:', totalPix.toFixed(2));
console.log('Depósitos:', totalDepositos.toFixed(2));
console.log('Transf. Recebidas:', totalTransfRecebidas.toFixed(2));
console.log('Transf. Entre CNPJs:', totalTransfEntreCnpjs.toFixed(2));
console.log('Movimento Calculado:', movimentoCalculado.toFixed(2));
console.log('Movimento Informado:', movimentoInformado.toFixed(2));
console.log('Diferença:', diferenca.toFixed(2));
console.log('Cálculo Correto?', diferenca < 0.01 ? '✅' : '❌');

// Retorna estrutura completa
return {
  // === IDENTIFICAÇÃO ===
  reportId: dadosOriginais.reportId,
  documentoIndex: dadosOriginais.documentoIndex,
  documentoNome: dadosOriginais.documentoNome,
  clienteId: dadosOriginais.clienteId,
  clienteNome: dadosOriginais.clienteNome,
  regimeTributario: dadosOriginais.regimeTributario,

  // === DADOS EXTRAÍDOS ===
  agenteProcessador: 'AGENTE_1_EXTRATOS',
  cnpj: dadosExtraidos.cnpj,
  razaoSocial: dadosExtraidos.razaoSocial,
  confiancaClassificacao: dadosOriginais.confianca,

  // Dados extraídos (spread mantém tudo)
  ...dadosExtraidos,

  // Validação de cálculo CORRIGIDA
  validacao: {
    movimentoCalculado: movimentoCalculado.toFixed(2).replace('.', ','),
    movimentoInformado: dadosExtraidos.totalMovimentoReal,
    diferencaAbsoluta: diferenca.toFixed(2),
    calculoCorreto: diferenca < 0.01,
    detalhamento: {
      vendasCartao: totalCartao.toFixed(2),
      pix: totalPix.toFixed(2),
      depositos: totalDepositos.toFixed(2),
      transferenciasRecebidas: totalTransfRecebidas.toFixed(2),
      transferenciasEntreCnpjs: totalTransfEntreCnpjs.toFixed(2)
    }
  },

  // Metadados
  timestampProcessamento: new Date().toISOString(),
  temErro: dadosExtraidos._erro || false,

  // Debug (remover em produção)
  _debug: {
    respostaOriginal: rawText.substring(0, 500),
    file_uri: dadosOriginais.file_uri
  }
};
